        // calculate the global thread coordination
	int data_94 = v_74+omp_get_thread_num();
	int val_4 = var_83+omp_get_thread_num();

        // load data if it is within the valid input range
	int elem_62=data_94, tmp_70=val_4;
        int val_97 = val_61*elem_62+tmp_70;

        float *data_84 = (float *)malloc(BLOCK_SIZE * BLOCK_SIZE * sizeof(float));
