            data_84[omp_get_thread_num()*BLOCK_SIZE + omp_get_thread_num()] = elem_14[val_97];  // Load the temperature data from global memory to shared memory
            elem_6[omp_get_thread_num()*BLOCK_SIZE + omp_get_thread_num()] = item_17[val_97];// Load the power data from global memory to shared memory
	}
	#pragma omp barrier

        // effective range within this block that falls within
        // the valid range of the input data
        // used to rule out computation outside the boundary.
        int x_72 = (0 > v_74) ? -v_74 : 0;
        int data_13 = (elem_93-1 < elem_21) ? BLOCK_SIZE-1-(elem_21-elem_93+1) : BLOCK_SIZE-1;
        int v_12 = (0 > var_83) ? -var_83 : 0;
        int x_33 = (val_61-1 < x_76) ? BLOCK_SIZE-1-(x_76-val_61+1) : BLOCK_SIZE-1;

        int N = omp_get_thread_num()-1;
        int S = omp_get_thread_num()+1;
        int W = omp_get_thread_num()-1;
        int E = omp_get_thread_num()+1;

        N = (x_72 > N) ? x_72 : N;
        S = (data_13 < S) ? data_13 : S;
        W = (v_12 > W) ? v_12 : W;
        E = (x_33 < E) ? x_33 : E;

        bool item_85;
        data_27=x_67/elem_3;

	var_54=1/tmp_71;
	elem_46=1/v_30;
	v_80=1/tmp_43;

        for (int i=0; var_86 > i ; i++){
