	       	         (data_84[S*BLOCK_SIZE + omp_get_thread_num()] + data_84[N*BLOCK_SIZE + omp_get_thread_num()] - 2.0*data_84[omp_get_thread_num()*BLOCK_SIZE + omp_get_thread_num()]) * elem_46 +
		             (data_84[omp_get_thread_num()*BLOCK_SIZE + E] + data_84[omp_get_thread_num()*BLOCK_SIZE + W] - 2.0*data_84[omp_get_thread_num()*BLOCK_SIZE + omp_get_thread_num()]) * var_54 +
		             (elem_65 - data_84[omp_get_thread_num()*BLOCK_SIZE + omp_get_thread_num()]) * v_80);

            }
            #pragma omp barrier
            if(var_86-1 == i)
                break;
            if(item_85)	 //Assign the computation range
                data_84[omp_get_thread_num()*BLOCK_SIZE + omp_get_thread_num()]= var_8[omp_get_thread_num()*BLOCK_SIZE + omp_get_thread_num()];
            #pragma omp barrier
          }

      // update the global memory
      // after the last iteration, only threads coordinated within the
      // small block perform the calculation and switch on ``computed''
      if (item_85){
          data_19[val_97]= var_8[omp_get_thread_num()*BLOCK_SIZE + omp_get_thread_num()];
      }

